import React, { useState, useEffect, useRef } from "react";
import netdropsLogo from "./Netdrops.jpg";

// 최대 동시 파일 전송 개수
const MAX_CONCURRENT_FILES = 30;

interface User {
  id: string;
  nickname: string;
  sessionId?: string; // 서버에서 init 메시지로 할당됨
  isOnline?: boolean;
}

// UUID 생성 함수 (RFC4122 v4)
const generateUUID = (): string =>
  "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === "x" ? r : ((r & 0x3) | 0x8);
    return v.toString(16);
  });

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [showTransferModal, setShowTransferModal] = useState(false);
  const [showWifiAlert, setShowWifiAlert] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [showContextMenu, setShowContextMenu] = useState<{ x: number; y: number } | null>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [modal, setModal] = useState({ visible: false, message: "" });
  const [showFileSelectModal, setShowFileSelectModal] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const ws = useRef<WebSocket | null>(null);
  const fileBuffersRef = useRef<ArrayBuffer[]>([]);

  const addSystemMessage = (message: string) => console.log("[System Message]:", message);
  const clearSearch = () => setSearchTerm("");

  const handleUserClick = (user: User) => {
    setSelectedUser(user);
    ws.current?.send(JSON.stringify({ type: "request", senderSessionId: currentUser?.sessionId, senderNickname: currentUser?.nickname, target: user.sessionId }));
    addSystemMessage("파일 전송 요청을 보냈습니다.");
  };

  useEffect(() => {
    ws.current = new WebSocket("ws://localhost:8080/ws");
    ws.current.binaryType = "arraybuffer";

    ws.current.onopen = () => addSystemMessage("서버에 연결되었습니다.");
    ws.current.onmessage = (event) => {
      if (typeof event.data === "string") {
        const data = JSON.parse(event.data);
        switch (data.type) {
          case "init":
            setCurrentUser({ id: data.sessionId, nickname: data.nickname, sessionId: data.sessionId, isOnline: true });
            addSystemMessage(`내 정보: ${data.nickname} (${data.sessionId})`);
            break;
          case "userList":
            setUsers(data.users);
            break;
          case "request":
            setSelectedUser({ id: data.senderSessionId, nickname: data.senderNickname, sessionId: data.senderSessionId });
            setShowTransferModal(true);
            addSystemMessage(`${data.senderNickname}님이 파일 전송을 요청했습니다.`);
            break;
          case "response":
            data.data.accepted
              ? (addSystemMessage("전송 요청이 수락되었습니다. 파일을 선택해주세요."), setShowFileSelectModal(true))
              : addSystemMessage("전송 요청이 거절되었습니다.");
            break;
          case "meta":
            fileBuffersRef.current = [];
            break;
          case "end":
            const blob = new Blob(fileBuffersRef.current);
            const url = URL.createObjectURL(blob);
            const a = document.createElement("a");
            a.href = url; a.download = "Netdrops_download.jpg"; document.body.appendChild(a); a.click();
            setTimeout(() => URL.revokeObjectURL(url), 100);
            break;
        }
      } else {
        fileBuffersRef.current.push(event.data as ArrayBuffer);
      }
    };
    ws.current.onerror = () => addSystemMessage("WebSocket 에러 발생");
    ws.current.onclose = () => addSystemMessage("연결이 종료되었습니다.");
    return () => ws.current?.close();
  }, []);

  const handleSendFiles = () => {
    if (!selectedFiles.length || !selectedUser) return;
    addSystemMessage(`Sending ${selectedFiles.length} files to ${selectedUser.nickname}...`);
    selectedFiles.forEach((file) => {
      const id = generateUUID();
      ws.current?.send(JSON.stringify({ type: "meta", fileId: id, target: selectedUser.sessionId }));
      const reader = new FileReader();
      reader.onload = () => {
        const buf = reader.result as ArrayBuffer;
        for (let off = 0; off < buf.byteLength; off += 150*1024) {
          ws.current?.send(buf.slice(off, off + 150*1024));
        }
        ws.current?.send(JSON.stringify({ type: "end", fileId: id, target: selectedUser.sessionId }));
      };
      reader.readAsArrayBuffer(file);
    });
    setShowFileSelectModal(false);
    setShowTransferModal(false);
    setSelectedFiles([]);
    setSelectedUser(null);
  };

  const handleTransferResponse = (accepted: boolean) => {
    ws.current?.send(JSON.stringify({ type: "response", data: { accepted }, target: selectedUser?.sessionId }));
    setShowTransferModal(false);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const arr = Array.from(e.target.files ?? []);
    if (arr.length > MAX_CONCURRENT_FILES) return alert("최대 30개까지 선택 가능합니다.");
    setSelectedFiles(arr);
    setShowFileSelectModal(false);
  };

  return (
    <div className="min-h-screen bg-transparent flex flex-col">
      {/* Header */}
      <header className="flex items-center p-4 bg-white shadow">
        <img src={netdropsLogo} className="w-10 h-10 mr-2" />
        <h1 className="text-2xl font-bold">Netdrops</h1>
      </header>
      {/* Search & User List */}
      <main className="flex-1 p-4 overflow-auto">
        <input
          value={searchTerm}
          onChange={e => setSearchTerm(e.target.value)}
          placeholder="닉네임 검색"
          className="w-full p-2 border rounded mb-4"
        />
        <div className="grid grid-cols-3 md:grid-cols-6 gap-4">
          {users.filter(u => u.sessionId !== currentUser?.sessionId)
            .filter(u => u.nickname.includes(searchTerm))
            .map(u => (
              <div
                key={u.id}
                className="bg-white p-4 rounded shadow cursor-pointer"
                onClick={() => handleUserClick(u)}
                onContextMenu={e => { e.preventDefault(); setShowContextMenu({ x:e.clientX,y:e.clientY }); setSelectedUser(u); }}
              >
                <div className="w-12 h-12 bg-primary rounded-full text-white flex items-center justify-center mb-2">
                  {u.nickname[0].toUpperCase()}
                </div>
                <div className="truncate">{u.nickname}</div>
              </div>
            ))}
        </div>
      </main>
      {/* Modals & Context Menu */}
      {showContextMenu && selectedUser && (
        <ul style={{ top: showContextMenu.y, left: showContextMenu.x }} className="fixed bg-white shadow rounded">
          <li onClick={() => { fileInputRef.current?.click(); setShowContextMenu(null); }} className="p-2 hover:bg-gray-100">Send Files</li>
          <li onClick={() => { setShowProfileModal(true); setShowContextMenu(null); }} className="p-2 hover:bg-gray-100">View Profile</li>
        </ul>
      )}
      {/* File Select Modal */}
      {showFileSelectModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center">
          <div className="bg-white p-4 rounded">
            <input ref={fileInputRef} type="file" multiple onChange={handleFileSelect} />
          </div>
        </div>
      )}
      {/* Transfer Request */}
      {showTransferModal && selectedUser && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center">
          <div className="bg-white p-4 rounded">
            <p>{selectedUser.nickname}님이 파일을 보냅니다. 수락?</p>
            <button onClick={() => handleTransferResponse(true)} className="mr-2 bg-blue-500 text-white px-2 rounded">Accept</button>
            <button onClick={() => handleTransferResponse(false)} className="bg-gray-300 px-2 rounded">Decline</button>
          </div>
        </div>
      )}
      {/* Profile Modal */}
      {showProfileModal && selectedUser && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center">
          <div className="bg-white p-4 rounded">
            <p>Nickname: {selectedUser.nickname}</p>
            <p>ID: {selectedUser.id}</p>
            <button onClick={() => setShowProfileModal(false)} className="mt-2 bg-gray-300 px-2 rounded">Close</button>
          </div>
        </div>
      )}
      {/* Hidden File Input for Trigger */}
      <input ref={fileInputRef} type="file" className="hidden" multiple accept="image/*" onChange={handleFileSelect} />
      {/* WiFi Alert Modal */}
      {showWifiAlert && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center">
          <div className="bg-white p-4 rounded">
            <p>같은 WiFi에 연결되어 있지 않습니다.</p>
            <button onClick={() => setShowWifiAlert(false)} className="mt-2 bg-blue-500 text-white px-2 rounded">OK</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
